// ENCAPSULATION PROCESS
BEGIN
 // Application Layer
 userData = "Web page request"
 data = userData // No change at Application

 // Presentation Layer - Add presentation header
 data = addHeader(data, "PRESENTATION")

 // Session Layer - Add session header 
 data = addHeader(data, "SESSION")

 // Transport Layer - Add TCP/UDP header (Segment/Datagram)
 data = addHeader(data, "TCP_HEADER: srcPort=, destPort=80")

 // Network Layer - Add IP header (Packet)
 data = addHeader(data, "IP_HEADER: srcIP=192.168.1.10, destIP=142.250.1.1")

 // Data Link Layer - Add frame header and trailer
 data = addHeader(data, "MAC_HEADER: srcMAC=AA:BB:CC, destMAC=DD:EE:FF")
 data = addTrailer(data, "FCS")

 // Physical Layer - Convert to bits
 bits = convertToBits(data)

 // Transmit bits over network
 TRANSMIT(bits)
END
